// Split the /alerts/pending response so downstream nodes run once per
// alert. Server already filtered by `olderThanMinutes=60`,
// `notYetRepeated=true`, `notSnoozed=true`. We keep all severities
// (P0..P3) here — repeat-ping is a generic accountability mechanic,
// not severity-gated. P0/P1 already saw T1 escalation 45 min ago via
// WF-103, but they still need T2 noise in the topic to surface the
// alert to operators who weren't paged.
const body = $input.first()?.json ?? {};
const alerts = Array.isArray(body.alerts) ? body.alerts : [];
return alerts.map((a) => ({ json: a }));

// Build the [⚠ REPEAT] broadcast body. We re-post to the SAME topic as
// the original alert (not founder DM — that's T1's job). Inline-keyboard
// drops `investigating` (operator already knows it's pending) and adds
// snooze 1h/4h so the operator can mute the next repeat-tick if they
// are actively working on it.
// `chatId` + `messageThreadId` come from the alert row's `metadata`,
// which broadcast workflows populate via the standard `Build alert
// payload` Code node (PR-2/PR-3/PR-4 wiring).
const alert = $('Split alerts').item.json;
const chatId = alert?.telegram_chat_id
  || alert?.metadata?.tgChatId
  || alert?.metadata?.chatId
  || $env?.SERGEANT_ALERT_OPS_CHAT_ID;
const messageThreadId = alert?.metadata?.tgMessageThreadId
  || alert?.metadata?.messageThreadId
  || null;
const posted = alert?.posted_at ? new Date(alert.posted_at) : null;
const minutesSincePost = posted ? Math.round((Date.now() - posted.getTime()) / 60000) : null;
const minutesLabel = minutesSincePost === null ? '?' : `${minutesSincePost}хв`;
const summary = (alert?.summary || '').slice(0, 3500);
const text = [
  `⚠ <b>REPEAT (${minutesLabel} без ack) — ${alert?.severity || 'P?'}</b>`,
  '',
  `<b>Topic:</b> ${alert?.topic || '—'}`,
  `<b>Alert ID:</b> <code>${alert?.alert_id || '—'}</code>`,
  '',
  summary || '<i>(no summary)</i>',
].join('\n');
const inlineKeyboard = [
  [
    { text: '✅ Прочитав', callback_data: `ack:r:${alert?.alert_id}` },
    { text: '🕐 Snooze 1h', callback_data: `snooze:1h:${alert?.alert_id}` },
    { text: '🕓 Snooze 4h', callback_data: `snooze:4h:${alert?.alert_id}` },
  ],
];
return [{ json: {
  chatId,
  messageThreadId,
  text,
  inlineKeyboard,
  alertId: alert?.alert_id,
} }];
